class CombinationIterator:
    def __init__(self, characters, combinationLength):
        self.chars = characters
        self.k = combinationLength
        n = len(characters)
        self.idx = list(range(combinationLength))
        self.n = n
        self.done = combinationLength > n
    def _current(self):
        return ''.join(self.chars[i] for i in self.idx)
    def next(self):
        val = self._current()
        j = self.k - 1
        while j >= 0 and self.idx[j] == self.n - self.k + j:
            j -= 1
        if j < 0:
            self.done = True
        else:
            self.idx[j] += 1
            for t in range(j + 1, self.k):
                self.idx[t] = self.idx[t - 1] + 1
        return val
    def hasNext(self):
        return not self.done

