var CombinationIterator = function(characters, combinationLength) {
    this.chars = characters;
    this.k = combinationLength;
    this.n = characters.length;
    this.idx = [];
    for (let i = 0; i < combinationLength; i++) this.idx.push(i);
    this.done = combinationLength > this.n;
};

CombinationIterator.prototype._current = function() {
    let s = '';
    for (const i of this.idx) s += this.chars[i];
    return s;
};

CombinationIterator.prototype.next = function() {
    const val = this._current();
    let j = this.k - 1;
    while (j >= 0 && this.idx[j] === this.n - this.k + j) j -= 1;
    if (j < 0) {
        this.done = true;
    } else {
        this.idx[j] += 1;
        for (let t = j + 1; t < this.k; t++) this.idx[t] = this.idx[t - 1] + 1;
    }
    return val;
};

CombinationIterator.prototype.hasNext = function() {
    return !this.done;
};
